import PropTypes from "prop-types"
import React from "react"
import scratchblocks from "scratchblocks"

const ScratchBlocks = ({
  blockStyle,
  languages,
  children,
  ...props
}) => {
  const ref = React.useRef(null)

  React.useEffect(() => {
    let options = {}
    if (blockStyle !== undefined) options.style = blockStyle
    if (languages !== undefined) options.languages = languages

    const doc = scratchblocks.parse(children, options)
    const svg = scratchblocks.render(doc, options)

    ref.current.innerHTML = ""
    ref.current.appendChild(svg)
  }, [blockStyle, languages, children])

  return <div ref={ref} {...props} />
}

function InnerScratchBlocksMDX({ children }) {
  return (
    <ScratchBlocks blockStyle="scratch3">{children}</ScratchBlocks>
  )
}

InnerScratchBlocksMDX.propTypes = {
  children: PropTypes.node.isRequired,
}

export default InnerScratchBlocksMDX;
